func IsApplicableTableForDB(val reflect.Value, db string) bool {
	if !val.IsValid() {
		return true
	}
	fun := val.MethodByName("IsApplicableTableForDB")
	if fun.IsValid() {
		vals := fun.Call([]reflect.Value{reflect.ValueOf(db)})
		if len(vals) > 0 && vals[0].Kind() == reflect.Bool {
			return vals[0].Bool()
		}
	}
	return true
}
